CREATE DATABASE RAPCHIEUPHIMCGV
GO


USE RAPCHIEUPHIMCGV
GO


--Bảng chi nhánh
create table CHI_NHANH
(        
        MaCN varchar (4) Primary key,
        TenCN NVARCHAR(50) NOT NULL,
        MaMien VARCHAR(2),
        MaTP VARCHAR(3),
        MaPQ VARCHAR(5)
)
go


--Bảng miền
CREATE TABLE MIEN
(
        MaMien VARCHAR(2) PRIMARY KEY,
        TenMien NVARCHAR(5) NOT NULL
)
GO


--Bảng thành phố
CREATE TABLE THANH_PHO
(
        MaTP VARCHAR(3) PRIMARY KEY,
        TenTP NVARCHAR(30) NOT NULL
);
GO


--Bảng quận
CREATE TABLE PHUONG_QUAN
(
        MaPQ VARCHAR(5) PRIMARY KEY,
        TenPQ NVARCHAR(30) NOT NULL
)
GO


--Bảng thời gian
CREATE TABLE THOI_GIAN
(
        MaTG varchar(8) PRIMARY KEY,
        NgayDayDu DATE,
        Nam INT,
        Quy INT,
        Thang INT,
        Ngay INT,
        Thu varchar (2),
        NgayTrongTuan INT,
        TuanTrongThang INT,
        TuanTrongNam INT
)
GO


--Bảng nhân viên
create table NHAN_VIEN
(        
        MaNV varchar(4) Primary key,
        HoTen nvarchar(50) not null,
        NgaySinh date not null,
        SDT char(10),
        GioiTinh nvarchar(3),
        SoGioLam float not null,
        MucLuong int not null,
)
go


--Bảng khách hàng
create table KHACH_HANG
(        
        MaKH varchar(5) primary key,
        HoTen nvarchar(50) not null,
        NamSinh int not null,
        GioiTinh nvarchar(3),
        MaLKH varchar(5),
)
GO


--Bảng loại khách hàng
create table LOAI_KHACH_HANG
(
        MaLKH varchar(5) primary key,
        TenLKH nvarchar (10) not null
)
go


--Bảng phim
create table PHIM
(        
        MaPhim varchar(3) primary key,
        TenPhim nvarchar(100) not null,
        NgayCongChieu date,
        DaoDien nvarchar(50) not null,
        MaTLP VARCHAR(4) not null,
        MaNSX VARCHAR(5) not null,
        MaGHDT VARCHAR(3) not null
)
go


--Bảng nhà sản xuất
CREATE TABLE NHA_SAN_XUAT
(
        MaNSX VARCHAR(5) PRIMARY KEY,
        TenNSX NVARCHAR(50) NOT NULL
)


--Bảng thể loại phim
CREATE TABLE THE_LOAI_PHIM
(
        MaTLP VARCHAR(4) PRIMARY KEY,
        TenTLP NVARCHAR(30) NOT NULL
)
GO


--Bảng giới hạn độ tuổi
CREATE TABLE GIOI_HAN_DO_TUOI
(
        MaGHDT VARCHAR(3) PRIMARY KEY,
        TenDoTuoi NVARCHAR(20) NOT NULL
)
GO


--Bảng suất chiếu
create table SUAT_CHIEU
(        
        MaSC varchar(4) primary key,
        ThoiGianBatDau time not null,
        ThoiGianKetThuc time not null
)
go


--Bảng phòng chiếu
create table PHONG_CHIEU
(        
        MaPC varchar(3) primary key,
        TenPC nvarchar(10) not null
)
go


--Bảng loại vé
create table LOAI_VE
(        
        MaLoaiVe varchar(3) primary key,
        TenLoaiVe nvarchar(20) not null,
        Gia int not null
)
go


--Bảng phương thức thanh toán
CREATE TABLE PHUONG_THUC_THANH_TOAN
(
        MaPTTT VARCHAR(4) PRIMARY KEY,
        TenPTTT NVARCHAR(50) NOT NULL
)
GO


--Bảng kết quả kinh doanh
create table KET_QUA_KINH_DOANH
(        
        MaHD varchar(6) primary key,
        MaKH varchar(5),
        MaNV varchar(4),
        MaCN varchar (4),
        MaTG varchar(8),
        MaPhim varchar(3),
        MaSC varchar(4),
        MaPC varchar(3),
        MaLoaiVe varchar(3),
        SoLuongVe INT,
        ThanhTien INT,
        MaPTTT VARCHAR(4),
)
go




