FOREIGN KEY (MaPQ) REFERENCES PHUONG_QUAN(MaPQ);


ALTER TABLE KHACH_HANG
ADD CONSTRAINT fk_LoaiKhachHang
FOREIGN KEY (MaLKH) REFERENCES LOAI_KHACH_HANG(MaLKH);


ALTER TABLE PHIM
ADD CONSTRAINT fk_TheLoaiPhim
FOREIGN KEY (MaTLP) REFERENCES THE_LOAI_PHIM(MaTLP);


ALTER TABLE PHIM
ADD CONSTRAINT fk_NhaSanXuat
FOREIGN KEY (MaNSX) REFERENCES NHA_SAN_XUAT(MaNSX);


ALTER TABLE PHIM
ADD CONSTRAINT fk_GioiHanDoTuoi
FOREIGN KEY (MaGHDT) REFERENCES GIOI_HAN_DO_TUOI(MaGHDT);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_KhachHang
FOREIGN KEY (MaKH) REFERENCES KHACH_HANG(MaKH);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_NhanVien
FOREIGN KEY (MaNV) REFERENCES NHAN_VIEN(MaNV);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_ChiNhanh
FOREIGN KEY (MaCN) REFERENCES CHI_NHANH(MaCN);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_ThoiGian
FOREIGN KEY (MaTG) REFERENCES THOI_GIAN(MaTG);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_Phim
FOREIGN KEY (MaPhim) REFERENCES PHIM(MaPhim);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_SuatChieu
FOREIGN KEY (MaSC) REFERENCES SUAT_CHIEU(MaSC);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_PhongChieu
FOREIGN KEY (MaPC) REFERENCES PHONG_CHIEU(MaPC);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_LoaiVe
FOREIGN KEY (MaLoaiVe) REFERENCES LOAI_VE(MaLoaiVe);


ALTER TABLE KET_QUA_KINH_DOANH
ADD CONSTRAINT fk_PhuongThucThanhToan
FOREIGN KEY (MaPTTT) REFERENCES PHUONG_THUC_THANH_TOAN(MaPTTT);